INSERT INTO PhieuXetNghiem VALUES ('1715', '54', '3', '43', 'Cach cua sau da cac rat tu.', 'Nguoi chua nhung dieu den.');
INSERT INTO PhieuXetNghiem VALUES ('1716', '1427', '3', '18', 'Nhung cua se tu lam cua dieu sau.', 'Nhu ma tu ve gan.');
INSERT INTO PhieuXetNghiem VALUES ('1717', '1310', '25', '38', 'Cung trong tai.', 'Rat cung cach the hon.');
INSERT INTO PhieuXetNghiem VALUES ('1718', '775', '27', '66', 'Ma de dang cai giua nhu khong.', 'Hoac toi cai cach.');
