INSERT INTO PhieuXetNghiem VALUES ('1721', '308', '22', '45', 'Khong thi theo tu.', 'Vai giong chi duoc sau nhieu ban.');
INSERT INTO PhieuXetNghiem VALUES ('1722', '1114', '20', '49', 'Cach nhu duoc hoac dang trong vi.', 'Co nhu lam cung cung hoac va nao.');
INSERT INTO PhieuXetNghiem VALUES ('1723', '377', '37', '32', 'Cung cua la nhu thay.', 'Vay tu cai ma.');
INSERT INTO PhieuXetNghiem VALUES ('1724', '943', '21', '19', 'Mot ve nao nay vi la.', 'Co thay nhu.');
INSERT INTO PhieuXetNghiem VALUES ('1725', '1180', '1', '3', 'De den duoi chua moi tung do do.', 'Tu hoac duoi.');
INSERT INTO PhieuXetNghiem VALUES ('1726', '1860', '45', '33', 'Giong cac tung neu tung cai dung.', 'Theo nhu la lam tu nhu.');
INSERT INTO PhieuXetNghiem VALUES ('1727', '1688', '31', '59', 'Trong se so tung vi ben nhu.', 'Do khong voi chua va.');
INSERT INTO PhieuXetNghiem VALUES ('1728', '9', '6', '29', 'Sau vi nhu nhung cung khien hon.', 'Giong cac nhu cach lon moi tu.');
