INSERT INTO PhieuXetNghiem VALUES ('1730', '1655', '24', '5', 'Nay nhu cua voi dang.', 'Ve de den cung thi nhieu nhu.');
INSERT INTO PhieuXetNghiem VALUES ('1731', '1602', '35', '68', 'Trong dang di cach cung dang.', 'Hon so chua hon ma.');
INSERT INTO PhieuXetNghiem VALUES ('1732', '1021', '45', '38', 'Giua co tu cach nguoi cua nao ve.', 'So va nguoi lam.');
