INSERT INTO PhieuXetNghiem VALUES ('1737', '1296', '15', '33', 'Duoc do da nguoi cho.', 'Trong lon cac cac gan noi.');
INSERT INTO PhieuXetNghiem VALUES ('1738', '1297', '12', '8', 'Ma noi di sau.', 'Duoi toi cung tu vi va dieu.');
INSERT INTO PhieuXetNghiem VALUES ('1739', '1899', '7', '69', 'Nhung dang rat sau duoc duoc mot.', 'Voi gan cua giong nguoi.');
