INSERT INTO PhieuXetNghiem VALUES ('1745', '1439', '20', '31', 'Nhu khien thay va.', 'Nhu nhu moi co da nguoi.');
INSERT INTO PhieuXetNghiem VALUES ('1746', '123', '26', '33', 'Khien giong tu neu tai.', 'Lon da sau khien lam.');
INSERT INTO PhieuXetNghiem VALUES ('1747', '483', '12', '20', 'Khien nhu nhung theo cach.', 'Hon thi hoac di di.');
INSERT INTO PhieuXetNghiem VALUES ('1748', '152', '45', '27', 'Dang di cua trong gan ve de.', 'Nhu lam cua sau voi tu cua.');
INSERT INTO PhieuXetNghiem VALUES ('1749', '1191', '33', '21', 'Mot neu ben dieu so de de.', 'Nhu thi cua nhu di do nhieu duoi.');
INSERT INTO PhieuXetNghiem VALUES ('1750', '1349', '21', '51', 'Ma sau chua se.', 'Chi khien moi vi duoi nhieu.');
INSERT INTO PhieuXetNghiem VALUES ('1751', '337', '15', '39', 'Tung nhu la.', 'Hon di nao voi nhu.');
INSERT INTO PhieuXetNghiem VALUES ('1752', '655', '25', '2', 'Khi cho thay dung voi nguoi.', 'Co van trong vai rat nhieu hon.');
