INSERT INTO PhieuXetNghiem VALUES ('1757', '1834', '40', '27', 'Nay sau cach dieu thi nay nhu.', 'Lon hoac cung la.');
INSERT INTO PhieuXetNghiem VALUES ('1758', '452', '32', '56', 'Voi cung toi cach ben la.', 'Tai hon the duoc di.');
INSERT INTO PhieuXetNghiem VALUES ('1759', '10', '24', '62', 'Khien voi tai lam.', 'La nhung duoi vai the gan cua.');
INSERT INTO PhieuXetNghiem VALUES ('1760', '134', '14', '48', 'Den nguoi trong toi tu cung chi.', 'Noi hon cung.');
INSERT INTO PhieuXetNghiem VALUES ('1761', '1479', '1', '68', 'The nguoi nao tu.', 'Giua tai neu do lam voi.');
