INSERT INTO PhieuXetNghiem VALUES ('1836', '1189', '27', '38', 'Cac nhu nhu nhung chi.', 'Co cung cach tu tu gan khong.');
INSERT INTO PhieuXetNghiem VALUES ('1837', '1285', '23', '49', 'Vai hon dang cua cua khi voi thay.', 'Se nay hon ban do nhu giong.');
