INSERT INTO PhieuXetNghiem VALUES ('1839', '1479', '11', '43', 'Neu co nhu cung trong.', 'Khien trong hon nhieu.');
INSERT INTO PhieuXetNghiem VALUES ('1840', '759', '39', '27', 'Tai di tu dieu nhieu cua vay tung.', 'Ban chi gan da so.');
INSERT INTO PhieuXetNghiem VALUES ('1841', '141', '28', '58', 'Tung tu cua nguoi.', 'Cho tai lam van co.');
INSERT INTO PhieuXetNghiem VALUES ('1842', '1756', '47', '10', 'Vi ma giong dung tai khong tung.', 'Moi noi hon chua voi ma nhung.');
