INSERT INTO PhieuXetNghiem VALUES ('1850', '1586', '18', '62', 'Lon toi khong do.', 'Cua cung nhu de duoc.');
INSERT INTO PhieuXetNghiem VALUES ('1851', '1937', '19', '15', 'Cac so trong nay.', 'Duoi noi trong lon voi nao nhu.');
