INSERT INTO PhieuXetNghiem VALUES ('1857', '935', '17', '11', 'Tu ban tu nhu so chua thay.', 'Van cung mot cach cai lam cua.');
INSERT INTO PhieuXetNghiem VALUES ('1858', '744', '37', '7', 'Tai cua cua cho nhu de.', 'Nhu ben den duoi do cac.');
