INSERT INTO PhieuXetNghiem VALUES ('1865', '277', '3', '19', 'Tu theo noi dung.', 'Cac chi trong ben nguoi mot.');
INSERT INTO PhieuXetNghiem VALUES ('1866', '1189', '18', '26', 'Nao ve giong mot ma giong nhu do.', 'The tu chi do sau voi co tu.');
