INSERT INTO PhieuXetNghiem VALUES ('2874', '41', '38', '3', 'Nao dung moi theo cai.', 'Nhu voi se.');
INSERT INTO PhieuXetNghiem VALUES ('2875', '1124', '33', '14', 'The nhung tai tu de cua cung.', 'Gan cac trong tu cho mot de.');
INSERT INTO PhieuXetNghiem VALUES ('2876', '759', '38', '42', 'Lon duoi neu thi trong.', 'Co vai de dung giua van.');
INSERT INTO PhieuXetNghiem VALUES ('2877', '814', '50', '39', 'Di ve moi de.', 'Giong thay cung sau co nhu.');
INSERT INTO PhieuXetNghiem VALUES ('2878', '122', '20', '5', 'Toi thay de hon.', 'Tu cho nhu hon nhu giua duoi.');
INSERT INTO PhieuXetNghiem VALUES ('2879', '716', '12', '2', 'Voi de mot rat.', 'Nhu rat nhung tu.');
INSERT INTO PhieuXetNghiem VALUES ('2880', '1668', '15', '38', 'Toi duoi voi tai.', 'Cach chua tu hoac do hoac dieu.');
INSERT INTO PhieuXetNghiem VALUES ('2881', '562', '11', '9', 'Nhieu neu rat de khi tung.', 'Nhung the nhieu vai.');
INSERT INTO PhieuXetNghiem VALUES ('2882', '1125', '14', '50', 'Cho so neu dang den cua.', 'Neu vai tai nhu cung dieu de.');
INSERT INTO PhieuXetNghiem VALUES ('2883', '746', '28', '44', 'Cac khong sau hon mot ma.', 'Tu moi trong cua thay.');
INSERT INTO PhieuXetNghiem VALUES ('2884', '292', '27', '66', 'So trong so toi khi.', 'Tu so thay co nhu.');
INSERT INTO PhieuXetNghiem VALUES ('2885', '649', '20', '45', 'Dieu tung ban co cac.', 'Voi nhieu tu nay voi thi nhieu hoac.');
INSERT INTO PhieuXetNghiem VALUES ('2886', '1908', '30', '25', 'So dang khi la.', 'Vai mot khien.');
INSERT INTO PhieuXetNghiem VALUES ('2887', '814', '24', '16', 'Khi tai hoac de nhu ve neu.', 'Nhu duoi hon nguoi ve nhung.');
INSERT INTO PhieuXetNghiem VALUES ('2888', '760', '27', '24', 'Nhu vi hon de neu cua cach nhu.', 'De vay de den cho cac.');
INSERT INTO PhieuXetNghiem VALUES ('2889', '1448', '36', '31', 'Duoi tu giua de hon nhu.', 'Chua ben thay nao.');
INSERT INTO PhieuXetNghiem VALUES ('2890', '1986', '6', '15', 'Di khong nhung moi.', 'Duoi vi cua hon.');
INSERT INTO PhieuXetNghiem VALUES ('2891', '1144', '8', '25', 'Ve cac cai de.', 'Cac vay tung giong va the.');
INSERT INTO PhieuXetNghiem VALUES ('2892', '357', '17', '25', 'Nhieu moi neu trong cac toi nay.', 'Di co chi giong.');
INSERT INTO PhieuXetNghiem VALUES ('2893', '1046', '37', '64', 'La se cai dung thi ve de noi.', 'Chi khong cua thay giong.');
INSERT INTO PhieuXetNghiem VALUES ('2894', '1801', '21', '4', 'Trong tai nhu tai.', 'Nhu so dieu lon.');
INSERT INTO PhieuXetNghiem VALUES ('2895', '879', '48', '12', 'Tu dung de vi cung lam cac.', 'Cac theo so khi neu khien co.');
INSERT INTO PhieuXetNghiem VALUES ('2896', '427', '44', '41', 'Ma mot cho cac gan.', 'Ma nhung duoi dieu de.');
INSERT INTO PhieuXetNghiem VALUES ('2897', '965', '21', '40', 'Dang de do rat thi chua tai.', 'Giong cung de se sau neu.');
INSERT INTO PhieuXetNghiem VALUES ('2898', '956', '11', '42', 'Cung vi co da lam cac den.', 'Vai cach sau de nhu co.');
INSERT INTO PhieuXetNghiem VALUES ('2899', '1080', '29', '36', 'Den de ma dieu.', 'Tu ma mot nhu sau nhieu nao.');
INSERT INTO PhieuXetNghiem VALUES ('2900', '1721', '9', '70', 'Mot tai chua la thi cung.', 'Mot dieu cai ban thi cung.');
INSERT INTO PhieuXetNghiem VALUES ('2901', '1113', '45', '50', 'Voi khien the cho cung khien ma co.', 'Voi trong ban vay cua neu.');
INSERT INTO PhieuXetNghiem VALUES ('2902', '1791', '45', '31', 'Cho nhu nhung la hoac thay.', 'Ve ban cua mot de hoac ma.');
INSERT INTO PhieuXetNghiem VALUES ('2903', '1405', '30', '40', 'Tu tai van co.', 'Neu giua nguoi cai do.');
INSERT INTO PhieuXetNghiem VALUES ('2904', '801', '21', '70', 'Trong thi cai tai nhung cach.', 'Khien vai va la khien hoac cung.');
INSERT INTO PhieuXetNghiem VALUES ('2905', '462', '17', '35', 'Nhu cua co hoac.', 'Dieu lam voi di do duoc.');
INSERT INTO PhieuXetNghiem VALUES ('2906', '1993', '1', '5', 'Chua hon neu.', 'Trong hon duoi giong cach tai.');
INSERT INTO PhieuXetNghiem VALUES ('2907', '99', '20', '27', 'Tung tai cua gan de de.', 'Khong cai di voi chi thay.');
INSERT INTO PhieuXetNghiem VALUES ('2908', '1758', '20', '38', 'Cho the nguoi tu den nhieu cung.', 'Co nguoi ve ma nhu.');
INSERT INTO PhieuXetNghiem VALUES ('2909', '92', '7', '30', 'Do ben voi vi nhu chua vi.', 'Dieu thi cung cho da ban voi toi.');
INSERT INTO PhieuXetNghiem VALUES ('2910', '998', '45', '41', 'Thay moi nay giong.', 'Co neu khi mot hon dang hon neu.');
INSERT INTO PhieuXetNghiem VALUES ('2911', '1301', '12', '31', 'Co de the da gan.', 'La de trong giua.');
INSERT INTO PhieuXetNghiem VALUES ('2912', '1450', '48', '48', 'Giua vay moi nao nhieu ma co.', 'Cach the dung nhu.');
INSERT INTO PhieuXetNghiem VALUES ('2913', '458', '2', '20', 'Co giong cach giua nhu nhu tung duoc.', 'De thay sau lam giua cho trong.');
INSERT INTO PhieuXetNghiem VALUES ('2914', '1884', '46', '4', 'So sau cua voi mot hon.', 'Cai hon ben thay.');
INSERT INTO PhieuXetNghiem VALUES ('2915', '1939', '41', '40', 'Voi co lon duoc thi mot lon.', 'Tu cai khi.');
INSERT INTO PhieuXetNghiem VALUES ('2916', '1675', '33', '44', 'Cung thay moi khi.', 'Va den de.');
INSERT INTO PhieuXetNghiem VALUES ('2917', '1718', '23', '41', 'Tu hon nhu.', 'Chua duoc vai.');
INSERT INTO PhieuXetNghiem VALUES ('2918', '668', '47', '37', 'Vai dung va voi de tu.', 'Lon so cung mot giong nay cai gan.');
INSERT INTO PhieuXetNghiem VALUES ('2919', '1559', '11', '23', 'Khi ban so ban dieu duoc the.', 'Rat toi tu duoi ban hon.');
INSERT INTO PhieuXetNghiem VALUES ('2920', '1550', '2', '52', 'Khien voi thay lam nay.', 'Ben la de nhu nhu vay tung.');
INSERT INTO PhieuXetNghiem VALUES ('2921', '1394', '8', '23', 'Vi khong ma va.', 'Gan trong chua cua de tu noi.');
INSERT INTO PhieuXetNghiem VALUES ('2922', '606', '6', '24', 'Di the vai hoac voi.', 'So cach cac toi cai tai se tu.');
INSERT INTO PhieuXetNghiem VALUES ('2923', '605', '43', '38', 'Voi duoc cua tai nguoi.', 'Trong da duoi toi tung.');
INSERT INTO PhieuXetNghiem VALUES ('2924', '437', '50', '18', 'Cai dung cua de van mot.', 'Voi de ban cua tai nhu do nguoi.');
INSERT INTO PhieuXetNghiem VALUES ('2925', '1013', '45', '28', 'Cai voi lon toi ma co.', 'Moi moi lon nhieu hoac cai nguoi.');
INSERT INTO PhieuXetNghiem VALUES ('2926', '13', '4', '58', 'Nay cac dieu de ben va.', 'Tu de cung thay nhu vai.');
INSERT INTO PhieuXetNghiem VALUES ('2927', '1479', '32', '59', 'Dang cung lon dang cai di.', 'La neu hoac ve hon den cung.');
INSERT INTO PhieuXetNghiem VALUES ('2928', '42', '42', '1', 'Tu rat se hoac chua.', 'Voi cai thi vai.');
INSERT INTO PhieuXetNghiem VALUES ('2929', '587', '26', '65', 'Toi co voi gan do duoi.', 'Chua tung cai khien gan khong.');
INSERT INTO PhieuXetNghiem VALUES ('2930', '918', '4', '43', 'Trong cac ve cach.', 'Hon dieu nhieu nhu tu.');
INSERT INTO PhieuXetNghiem VALUES ('2931', '841', '11', '4', 'Cung va trong va la van.', 'Nhu vay nguoi nhu thay de.');
INSERT INTO PhieuXetNghiem VALUES ('2932', '187', '25', '2', 'Sau nguoi cac cung hoac thay va.', 'Vai cai tai ve.');
INSERT INTO PhieuXetNghiem VALUES ('2933', '1355', '50', '67', 'Giong tai thay hon nhu rat.', 'De cua nao nao dang.');
INSERT INTO PhieuXetNghiem VALUES ('2934', '1019', '8', '37', 'Thay khi se nhu mot.', 'Cach tung cua lon de nhu de vi.');
INSERT INTO PhieuXetNghiem VALUES ('2935', '917', '28', '32', 'Nao noi de nguoi chua tai va.', 'Duoi di hon nhu.');
INSERT INTO PhieuXetNghiem VALUES ('2936', '1441', '25', '54', 'Theo chi thay gan nhieu.', 'Khong tu da.');
INSERT INTO PhieuXetNghiem VALUES ('2937', '1820', '6', '63', 'Tu nhieu van van.', 'Dung den dieu the.');
INSERT INTO PhieuXetNghiem VALUES ('2938', '1601', '23', '30', 'Dang so khien.', 'Theo do cua hoac.');
INSERT INTO PhieuXetNghiem VALUES ('2939', '1274', '3', '68', 'Van the vai voi nhu va ma tai.', 'Sau de cua nay hon.');
INSERT INTO PhieuXetNghiem VALUES ('2940', '1875', '19', '36', 'Hon gan tu la.', 'Di cung vai khong ban ban chua.');
INSERT INTO PhieuXetNghiem VALUES ('2941', '859', '47', '46', 'Thay trong neu va cua nhu.', 'Cua vay cua voi da hoac duoi.');
INSERT INTO PhieuXetNghiem VALUES ('2942', '1698', '28', '42', 'Ve se se giong sau nhieu nhu.', 'Do de lon vi.');
INSERT INTO PhieuXetNghiem VALUES ('2943', '1016', '11', '35', 'Ban tu voi theo cua voi.', 'Thi tung cua nay van dung cung.');
INSERT INTO PhieuXetNghiem VALUES ('2944', '1258', '19', '69', 'Nhu ben giong hon chi duoc se.', 'Vai co da trong.');
INSERT INTO PhieuXetNghiem VALUES ('2945', '1216', '6', '62', 'Cac tung nhu khien khien tai lam de.', 'Thay voi co noi.');
INSERT INTO PhieuXetNghiem VALUES ('2946', '222', '31', '13', 'Dang toi nhung duoc neu.', 'La giong cua van tu voi.');
INSERT INTO PhieuXetNghiem VALUES ('2947', '682', '30', '8', 'Cach cung voi tu cho.', 'Nhu sau di co vi.');
INSERT INTO PhieuXetNghiem VALUES ('2948', '788', '2', '57', 'Lon cung cua hoac voi.', 'De thi noi.');
INSERT INTO PhieuXetNghiem VALUES ('2949', '640', '7', '11', 'Cung va tu nguoi vay.', 'Da ve lon di se moi.');
INSERT INTO PhieuXetNghiem VALUES ('2950', '1559', '39', '48', 'Khong voi ban hon cua.', 'Tung nay ben duoi tu nhieu nhieu voi.');
INSERT INTO PhieuXetNghiem VALUES ('2951', '161', '7', '28', 'Khien toi hon tu.', 'Duoi hoac voi di nhu cac de.');
INSERT INTO PhieuXetNghiem VALUES ('2952', '1317', '29', '17', 'Do den neu den ve vay ban.', 'Nhung theo giua nhu.');
INSERT INTO PhieuXetNghiem VALUES ('2953', '783', '40', '63', 'Thay de cai cung.', 'Cach nhieu voi cua gan.');
INSERT INTO PhieuXetNghiem VALUES ('2954', '1619', '33', '58', 'Nhieu di dung khi moi noi trong vai.', 'Tu van de khien ma.');
INSERT INTO PhieuXetNghiem VALUES ('2955', '1020', '38', '26', 'Vi nhu da giong voi rat.', 'Tu tung se theo so noi trong.');
INSERT INTO PhieuXetNghiem VALUES ('2956', '830', '27', '37', 'Ben khong hoac duoi co cua duoc.', 'De cung dung noi khi toi tung.');
INSERT INTO PhieuXetNghiem VALUES ('2957', '26', '44', '55', 'Thi toi khong.', 'Da dung toi van giong tu thay.');
INSERT INTO PhieuXetNghiem VALUES ('2958', '1972', '48', '40', 'Co nhu noi sau de nhu giua chua.', 'Co nhieu giua nhung.');
INSERT INTO PhieuXetNghiem VALUES ('2959', '842', '28', '38', 'Vai tung nhu chi cach hoac va.', 'Toi dang chi duoi.');
INSERT INTO PhieuXetNghiem VALUES ('2960', '226', '19', '50', 'Di dang khong.', 'Hon cua van tai mot cua.');
INSERT INTO PhieuXetNghiem VALUES ('2961', '110', '47', '9', 'Gan ve cac vi.', 'Cung neu tung noi da mot.');
INSERT INTO PhieuXetNghiem VALUES ('2962', '1300', '45', '23', 'Cac de trong cua voi dieu hon.', 'Hon cac de lam tung nhu de.');
INSERT INTO PhieuXetNghiem VALUES ('2963', '297', '37', '37', 'Cung giua tu dung co vay.', 'Nhung neu se cach do.');
INSERT INTO PhieuXetNghiem VALUES ('2964', '1894', '45', '13', 'Tung nao voi noi.', 'Nguoi khien tu.');
INSERT INTO PhieuXetNghiem VALUES ('2965', '1988', '25', '43', 'Voi rat trong dieu nhung thi vi.', 'Chi nhu cua.');
INSERT INTO PhieuXetNghiem VALUES ('2966', '160', '23', '35', 'Nhu tu de hon cua.', 'Duoc cai cai.');
INSERT INTO PhieuXetNghiem VALUES ('2967', '199', '22', '6', 'Trong nao hon nay chua so dang.', 'Cua den cua moi.');
INSERT INTO PhieuXetNghiem VALUES ('2968', '403', '39', '25', 'Co so nhieu den rat voi.', 'Vi da cung nao duoi cach giua.');
INSERT INTO PhieuXetNghiem VALUES ('2969', '540', '27', '48', 'Den dung ben cho nhu duoc vay.', 'Dung nhu chua vai nguoi thay de.');
INSERT INTO PhieuXetNghiem VALUES ('2970', '413', '36', '22', 'Ve ma giua so rat van de.', 'Ve trong chua theo.');
INSERT INTO PhieuXetNghiem VALUES ('2971', '165', '5', '22', 'Hoac trong giua tai chua cac cua so.', 'Se duoi co gan do.');
INSERT INTO PhieuXetNghiem VALUES ('2972', '1314', '3', '17', 'La theo chi noi nhu de.', 'Trong theo co nhu.');
INSERT INTO PhieuXetNghiem VALUES ('2973', '1691', '40', '14', 'Lam den nay vai cung tu.', 'Chua cua giua van.');
INSERT INTO PhieuXetNghiem VALUES ('2974', '1761', '40', '17', 'Ben voi dang di.', 'Hon ben cung giua tai tu.');
INSERT INTO PhieuXetNghiem VALUES ('2975', '680', '8', '7', 'Van nhu so thi thi.', 'Giong thay khong dung theo cung.');
INSERT INTO PhieuXetNghiem VALUES ('2976', '1714', '1', '16', 'Duoi cach khien tu de se.', 'Cung theo ben cua so voi voi.');
INSERT INTO PhieuXetNghiem VALUES ('2977', '1909', '31', '66', 'Nao vi hoac vi tu.', 'Dieu dang co giong tung vay hon.');
INSERT INTO PhieuXetNghiem VALUES ('2978', '967', '8', '13', 'Thay co nay the khien vay de.', 'Di rat cua de cach thay.');
INSERT INTO PhieuXetNghiem VALUES ('2979', '1385', '46', '4', 'De khi so khong sau co.', 'So se tu the.');
INSERT INTO PhieuXetNghiem VALUES ('2980', '15', '35', '28', 'Voi tung nhu de khi cach.', 'Khien dung moi cung nhu nhieu voi.');
INSERT INTO PhieuXetNghiem VALUES ('2981', '856', '18', '51', 'Nhieu co lon dieu toi duoc sau tung.', 'Den tai cho tu.');
INSERT INTO PhieuXetNghiem VALUES ('2982', '1434', '27', '19', 'Co tu mot thi nhu se.', 'Trong lam cung cai the co chi.');
INSERT INTO PhieuXetNghiem VALUES ('2983', '1976', '1', '11', 'Nhu khien trong.', 'Dung vai de trong cach duoi de nhu.');
INSERT INTO PhieuXetNghiem VALUES ('2984', '1900', '29', '42', 'Dang hon nhu cua.', 'So khong cua giua nay de.');
INSERT INTO PhieuXetNghiem VALUES ('2985', '853', '18', '24', 'Cua cua theo cho den.', 'De dang cai khi hoac duoc hon the.');
INSERT INTO PhieuXetNghiem VALUES ('2986', '58', '40', '40', 'Cung khi the hoac di tu voi ve.', 'Da giua gan se nay ma cung dang.');
INSERT INTO PhieuXetNghiem VALUES ('2987', '646', '10', '19', 'Cua duoc ve di nay.', 'Lam giong chua ban den.');
INSERT INTO PhieuXetNghiem VALUES ('2988', '1250', '32', '4', 'Vi ma lam cua.', 'Do gan cua se.');
INSERT INTO PhieuXetNghiem VALUES ('2989', '375', '43', '59', 'Nao de nhung ban.', 'Chi dieu rat tu di theo.');
INSERT INTO PhieuXetNghiem VALUES ('2990', '452', '4', '6', 'Gan khong cach cung khi lon nhu.', 'La da da giua.');
